async (page) => {
  const result = await page.evaluate((name) => JSON.stringify(window.__interactNPC(name)), 'Billey');
  await page.waitForTimeout(2000);
  return result;
}

async (page) => {
  const result = await page.evaluate((id) => window.__talkToNPC(id), '1-33937619');
  await page.waitForTimeout(2000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({
    result,
    pos: parsed.player_position,
    quest_panel: parsed.ui_state.quest_panel_visible,
    dialogue: parsed.ui_state.npc_dialogue,
    quest_stage: parsed.quests.find(q => q.key === 'desertquest')
  });
}

